  "inlineSchema": "// ─────────────────────────────────────────────────────────────\n// schema.prisma — Phase 1 patch\n// Basé sur le schéma existant (avec GameWorld/PlayerWorld)\n// Ajouts : wallLevel, farmLevel, stableLevel, rallyPointLevel,\n//          loyaltyPoints sur Village ; attackPoints/defensePoints\n//          sur Player ; morale/wallBonus sur AttackReport ;\n//          BuildingQueueItem (multi-slots).\n// ─────────────────────────────────────────────────────────────\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\n// ── Monde de jeu (existant, inchangé) ───────────────────────\nmodel GameWorld {\n  id          String    @id @default(uuid())\n  name        String    @unique\n  description String    @default(\"\")\n  gameSpeed   Float     @default(1.0)\n  mapSize     Int       @default(100)\n  maxPlayers  Int       @default(500)\n  isOpen      Boolean   @default(true)\n  startsAt    DateTime  @default(now())\n  endsAt      DateTime?\n\n  villages Village[]\n  players  PlayerWorld[]\n\n  createdAt DateTime @default(now())\n}\n\nmodel PlayerWorld {\n  player   Player    @relation(fields: [playerId], references: [id], onDelete: Cascade)\n  playerId String\n  world    GameWorld @relation(fields: [worldId], references: [id], onDelete: Cascade)\n  worldId  String\n  joinedAt DateTime  @default(now())\n\n  @@id([playerId, worldId])\n}\n\n// ── Joueur ───────────────────────────────────────────────────\nmodel Player {\n  id            String        @id @default(uuid())\n  username      String        @unique\n  email         String        @unique\n  password      String\n  villages      Village[]\n  worlds        PlayerWorld[]\n  createdAt     DateTime      @default(now())\n  totalPoints   Int           @default(0)\n  attackPoints  Int           @default(0) // ← NOUVEAU : kills offensifs\n  defensePoints Int           @default(0) // ← NOUVEAU : kills défensifs\n}\n\n// ── Village ──────────────────────────────────────────────────\nmodel Village {\n  id   String @id @default(uuid())\n  name String\n  x    Int\n  y    Int\n\n  wood  Float @default(500)\n  stone Float @default(500)\n  iron  Float @default(400)\n  food  Float @default(100)\n\n  timberCampLevel Int @default(1)\n  quarryLevel     Int @default(1)\n  ironMineLevel   Int @default(1)\n\n  // ── NOUVEAUX BÂTIMENTS ──────────────────────────────────\n  wallLevel       Int @default(0) // Mur : +5% défense/niveau (max 20)\n  farmLevel       Int @default(1) // Ferme : cap population\n  stableLevel     Int @default(0) // Écuries : prérequis cavalerie\n  rallyPointLevel Int @default(0) // Place d'armes : prérequis attaque\n\n  // ── Conquête (phase 3) ──────────────────────────────────\n  loyaltyPoints Int @default(100) // 0 = village conquis par le Noble\n\n  isAbandoned    Boolean @default(false)\n  abandonedLevel Int     @default(1)\n\n  shieldUntil DateTime?\n  lastTick    DateTime  @default(now())\n\n  player   Player? @relation(fields: [playerId], references: [id], onDelete: Cascade)\n  playerId String?\n\n  world   GameWorld? @relation(fields: [worldId], references: [id])\n  worldId String?\n\n  buildings    BuildingInstance[]\n  buildQueue   BuildingQueue? // ← legacy, conservé pendant la migration\n  buildItems   BuildingQueueItem[] // ← NOUVEAU : multi-slots\n  troops       Troop[]\n  recruitQueue RecruitQueue?\n\n  attacksSent     AttackReport[] @relation(\"AttackerVillage\")\n  attacksReceived AttackReport[] @relation(\"DefenderVillage\")\n\n  activeAttacksSent     ActiveAttack[] @relation(\"ActiveAttackAttacker\")\n  activeAttacksReceived ActiveAttack[] @relation(\"ActiveAttackDefender\")\n\n  @@unique([x, y])\n}\n\n// ── Instances de bâtiments (existant, inchangé) ─────────────\nmodel BuildingInstance {\n  id         String @id @default(uuid())\n  buildingId String\n  level      Int    @default(0)\n\n  village   Village @relation(fields: [villageId], references: [id], onDelete: Cascade)\n  villageId String\n\n  updatedAt DateTime @updatedAt\n\n  @@unique([villageId, buildingId])\n}\n\n// ── File construction legacy (1 slot) ───────────────────────\n// Conservée pendant la migration. À supprimer après validation.\nmodel BuildingQueue {\n  id          String @id @default(uuid())\n  buildingId  String\n  targetLevel Int\n\n  startsAt DateTime @default(now())\n  endsAt   DateTime\n\n  village   Village @relation(fields: [villageId], references: [id], onDelete: Cascade)\n  villageId String  @unique\n}\n\n// ── File construction multi-slots (NOUVEAU) ──────────────────\nmodel BuildingQueueItem {\n  id          String @id @default(uuid())\n  buildingId  String\n  targetLevel Int\n  position    Int    @default(0) // 0 = en cours, 1+ = en attente\n\n  startsAt DateTime @default(now())\n  endsAt   DateTime\n\n  village   Village @relation(fields: [villageId], references: [id], onDelete: Cascade)\n  villageId String\n\n  @@index([villageId, position])\n}\n\n// ── Troupes (existant, inchangé) ────────────────────────────\nmodel Troop {\n  id       String @id @default(uuid())\n  unitType String\n  count    Int    @default(0)\n\n  village   Village @relation(fields: [villageId], references: [id], onDelete: Cascade)\n  villageId String\n\n  @@unique([villageId, unitType])\n}\n\n// ── File de recrutement (existant, inchangé) ─────────────────\nmodel RecruitQueue {\n  id       String @id @default(uuid())\n  unitType String\n  count    Int\n  trained  Int    @default(0)\n\n  startsAt DateTime @default(now())\n  endsAt   DateTime\n\n  village   Village @relation(fields: [villageId], references: [id], onDelete: Cascade)\n  villageId String  @unique\n}\n\n// ── Rapports de combat ───────────────────────────────────────\nmodel AttackReport {\n  id String @id @default(uuid())\n\n  attackerVillage   Village @relation(\"AttackerVillage\", fields: [attackerVillageId], references: [id], onDelete: Cascade)\n  attackerVillageId String\n\n  defenderVillage   Village @relation(\"DefenderVillage\", fields: [defenderVillageId], references: [id], onDelete: Cascade)\n  defenderVillageId String\n\n  unitsSent           Json\n  unitsSurvived       Json\n  defenderUnitsBefore Json\n  defenderUnitsAfter  Json\n  resourcesLooted     Json\n\n  morale       Float   @default(1.0) // ← NOUVEAU\n  wallBonus    Float   @default(1.0) // ← NOUVEAU\n  pointsLost   Int     @default(0)\n  pointsGained Int     @default(0)\n  attackerWon  Boolean\n\n  createdAt DateTime @default(now())\n}\n\n// ── Attaques actives (existant, inchangé) ───────────────────\nmodel ActiveAttack {\n  id String @id @default(uuid())\n\n  attackerVillage   Village @relation(\"ActiveAttackAttacker\", fields: [attackerVillageId], references: [id], onDelete: Cascade)\n  attackerVillageId String\n\n  defenderVillage   Village @relation(\"ActiveAttackDefender\", fields: [defenderVillageId], references: [id], onDelete: Cascade)\n  defenderVillageId String\n\n  units     Json\n  survivors Json?\n\n  departsAt DateTime @default(now())\n  arrivesAt DateTime\n\n  status String @default(\"traveling\")\n}\n",
